# ----- Session Management -----
class RedisSessionManager:
    """Manages user sessions stored in Redis."""

    def __init__(self, client, prefix=SESSION_PREFIX, expiry=SESSION_EXPIRY):
        self.client = client
        self.prefix = prefix
        self.expiry = expiry

    def _get_session_key(self, session_id):
        return f"{self.prefix}{session_id}"

    def create_session(self, user_data):
        """Create a new session and return the session ID."""
        session_id = str(uuid.uuid4())
        session_key = self._get_session_key(session_id)
        session_data = {
            "session_id": session_id,
            "created_at": datetime.utcnow().isoformat(),
            "last_accessed": datetime.utcnow().isoformat(),
            "data": user_data
        }
        # Use SET with expiry for automatic session cleanup
        self.client.set(
            session_key,
            json.dumps(session_data),
            ex=self.expiry
        )
        return session_id

    def get_session(self, session_id):
        """Retrieve session data by session ID."""
        session_key = self._get_session_key(session_id)
        session_raw = self.client.get(session_key)
        if session_raw is None:
            return None
        session_data = json.loads(session_raw)
        # Update last accessed time and refresh expiry
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        self.client.set(session_key, json.dumps(session_data), ex=self.expiry)
        return session_data

    def update_session(self, session_id, update_data):
        """Update session data."""
        session_data = self.get_session(session_id)
        if session_data is None:
            return None
        session_data["data"].update(update_data)
        session_data["last_accessed"] = datetime.utcnow().isoformat()
        session_key = self._get_session_key(session_id)
        self.client.set(session_key, json.dumps(session_data), ex=self.expiry)
        return session_data

    def destroy_session(self, session_id):
        """Delete a session."""
        session_key = self._get_session_key(session_id)
        return self.client.delete(session_key) > 0

    def get_active_session_count(self):
        """Get count of active sessions (for monitoring)."""
        keys = self.client.keys(f"{self.prefix}*")
        return len(keys)


# Initialize session manager
session_manager = RedisSessionManager(redis_client)


# ----- Caching Decorator -----
def redis_cache(expiry=CACHE_DEFAULT_EXPIRY, key_prefix=CACHE_PREFIX):
    """
    Caching decorator for expensive database queries or computations.
    
    Usage:
        @redis_cache(expiry=600)
        def get_user_profile(user_id):
            # expensive database query
            return result
    """
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            # Build a unique cache key from function name and arguments
            cache_key_parts = [key_prefix, func.__name__]
            if args:
                cache_key_parts.extend([str(a) for a in args])
            if kwargs:
                sorted_kwargs = sorted(kwargs.items())
                cache_key_parts.extend([f"{k}={v}" for k, v in sorted_kwargs])
            cache_key = ":".join(cache_key_parts)

            try:
                # Try to get from cache
                cached_result = redis_client.get(cache_key)
                if cached_result is not None:
                    result = json.loads(cached_result)
                    result["_cache_hit"] = True
                    return result
            except (redis.ConnectionError, redis.TimeoutError):
                # If Redis is down, fall through to the actual function
                pass

            # Execute the actual function
            result = func(*args, **kwargs)

            try:
                # Store result in cache
                redis_client.set(cache_key, json.dumps(result), ex=expiry)
            except (redis.ConnectionError, redis.TimeoutError):
                # If Redis is down, just return the result without caching
                pass

            result["_cache_hit"] = False
            return result

        # Add cache invalidation helper
        def invalidate(*args, **kwargs):
            """Invalidate cached result for specific arguments."""
            cache_key_parts = [key_prefix, func.__name__]
            if args:
                cache_key_parts.extend([str(a) for a in args])
            if kwargs:
                sorted_kwargs = sorted(kwargs.items())
                cache_key_parts.extend([f"{k}={v}" for k, v in sorted_kwargs])
            cache_key = ":".join(cache_key_parts)
            return redis_client.delete(cache_key) > 0

        def invalidate_all():
            """Invalidate all cached results for this function."""
            pattern = f"{key_prefix}{func.__name__}:*"
            keys = redis_client.keys(pattern)
            if keys:
                return redis_client.delete(*keys)
            return 0

        wrapper.invalidate = invalidate
        wrapper.invalidate_all = invalidate_all
        return wrapper
    return decorator


# ----- Rate Limiter using Redis -----
class RateLimiter:
    """Simple rate limiter using Redis sliding window."""

    def __init__(self, client, max_requests=100, window_seconds=60):
        self.client = client
        self.max_requests = max_requests
        self.window_seconds = window_seconds

    def is_allowed(self, identifier):
        """Check if the request is allowed under rate limits."""
        key = f"ratelimit:{identifier}"
        now = time.time()
        pipe = self.client.pipeline()
        try:
            # Remove old entries outside the window
            pipe.zremrangebyscore(key, 0, now - self.window_seconds)
            # Add current request
            pipe.zadd(key, {str(now): now})
            # Count requests in window
            pipe.zcard(key)
            # Set expiry on the key
            pipe.expire(key, self.window_seconds)
            results = pipe.execute()
            request_count = results[2]
            return request_count <= self.max_requests
        except (redis.ConnectionError, redis.TimeoutError):
            # If Redis is down, allow the request (fail-open)
            return True


rate_limiter = RateLimiter(redis_client, max_requests=100, window_seconds=60)


