@app.before_request
def before_request():
    """Check rate limiting and load session before each request."""
    # Rate limiting
    client_ip = request.remote_addr
    if not rate_limiter.is_allowed(client_ip):
        return jsonify({"error": "Rate limit exceeded. Try again later."}), 429

    # Load session from header
    session_id = request.headers.get("X-Session-ID")
    if session_id:
        g.session_data = session_manager.get_session(session_id)
        g.session_id = session_id
    else:
        g.session_data = None
        g.session_id = None


