# --- Bulk Operations Demo ---
@app.route("/api/demo/pipeline", methods=["GET"])
def pipeline_demo():
    """Demonstrate Redis pipeline for batch operations (useful for high-traffic)."""
    start_time = time.time()

    # Using pipeline for batch operations reduces round trips
    pipe = redis_client.pipeline()
    for i in range(100):
        pipe.set(f"demo:key:{i}", f"value_{i}", ex=60)
    pipe.execute()

    # Batch GET
    pipe = redis_client.pipeline()
    for i in range(100):
        pipe.get(f"demo:key:{i}")
    results = pipe.execute()

    elapsed = time.time() - start_time

    # Cleanup
    pipe = redis_client.pipeline()
    for i in range(100):
        pipe.delete(f"demo:key:{i}")
    pipe.execute()

    return jsonify({
        "message": "Pipeline demo: 100 SET + 100 GET operations",
        "sample_results": results[:5],
        "total_time_ms": round(elapsed * 1000, 2),
        "avg_per_operation_ms": round(elapsed * 1000 / 200, 4)
    }), 200


